class Solution:
    def kthCharacter(self, k: int, operations: List[int]) -> str:
        word = "a"
        for operation in operations:
            if operation == 0:
                word += word
            else:
                word += chr((ord(word[0]) - ord('a') + 1) % 26 + ord('a')) + word
        return word[k - 1]
